code = """import json, re, pandas as pd

def load_maybe_path(obj):
    if isinstance(obj, str) and obj.endswith('.json'):
        with open(obj, 'r') as f:
            return json.load(f)
    return obj

clinical = load_maybe_path(var_call_H5tSHlQOoNNapA4XwIwJow8J)
cdh1 = load_maybe_path(var_call_4xe2SQ06FPhr8aa07QrgIkRa)

cdf = pd.DataFrame(clinical)
mdf = pd.DataFrame(cdh1)

# extract TCGA barcode from participant description
cdf['barcode'] = cdf['participant'].str.extract(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')[0]

# alive: days_to_death is [Not Applicable] or null
cdf['alive'] = cdf['days_to_death'].astype(str).str.contains('Not Applicable', case=False, na=False)

alive_df = cdf[cdf['alive'] & cdf['barcode'].notna()].copy()

mdf['barcode'] = mdf['participant']
mdf['has_cdh1'] = mdf['has_cdh1'].astype(int)

alive_df = alive_df.merge(mdf[['barcode','has_cdh1']], on='barcode', how='left')
alive_df['has_cdh1'] = alive_df['has_cdh1'].fillna(0).astype(int)

# compute percentages by histological type
alive_df['hist_type'] = alive_df['hist_type'].fillna('Unknown')

g = alive_df.groupby('hist_type').agg(n_alive=('barcode','nunique'), n_cdh1=('has_cdh1','sum'))
g['pct_cdh1'] = (g['n_cdh1'] / g['n_alive'] * 100).round(2)

# consider only hist types with at least 5 alive patients to avoid tiny denominators
# but question doesn't specify; keep all, then sort by pct desc, then n_alive desc
out = g.reset_index().sort_values(['pct_cdh1','n_alive'], ascending=[False, False]).head(3)

result = out.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(result))"""

